// AUTO-GENERATED cross-verification vectors produced from go-qrllib's
// crypto/internal/mlkem1024 (GenerateKeyInternal + EncapsulateInternal),
// which is itself validated against the NIST ACVP and Wycheproof vectors.
// Regenerate with the throwaway program in the commit message; do not edit by hand.
//
// Each vector asserts that rust-qrllib's ML-KEM-1024 produces byte-identical
// encapsulation keys, ciphertexts, and shared secrets to go-qrllib.

use qrllib::{DecapsulationKey, EncapsulationKey};

struct CrossVector {
    seed: &'static str,
    message: &'static str,
    encapsulation_key: &'static str,
    shared_key: &'static str,
    ciphertext: &'static str,
}

const CROSS_VECTORS: &[CrossVector] = &[
    CrossVector {
        seed: "000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f",
        message: "000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f",
        encapsulation_key: "",
        shared_key: "738a88cd9a25861e9a37c65a67ec1b39f069aed9646ede89410ace47a96a9b57",
        ciphertext: "",
    },
    CrossVector {
        seed: "000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f202122232425262728292a2b2c2d2e2f303132333435363738393a3b3c3d3e3f",
        message: "fffefdfcfbfaf9f8f7f6f5f4f3f2f1f0efeeedecebeae9e8e7e6e5e4e3e2e1e0",
        encapsulation_key: "",
        shared_key: "323e526bcf53a6354dc3e74722383f34fc1aa2de0dc6af18378a9c25ec7d96a2",
        ciphertext: "",
    },
    CrossVector {
        seed: "a5a4a7a6a1a0a3a2adacafaea9a8abaab5b4b7b6b1b0b3b2bdbcbfbeb9b8bbba5a5b58595e5f5c5d52535051565754554a4b48494e4f4c4d4243404146474445",
        message: "010003020504070609080b0a0d0c0f0e111013121514171619181b1a1d1c1f1e",
        encapsulation_key: "",
        shared_key: "9562dd619ef4fa29e2207aa4b89e44785fa42cfccc99d4c3a20f170b72fcc0a5",
        ciphertext: "",
    },
];

fn decode(value: &str) -> Vec<u8> {
    hex::decode(value).expect("hex vector")
}

#[test]
fn mlkem1024_matches_go_qrllib_byte_for_byte() {
    for (index, vector) in CROSS_VECTORS.iter().enumerate() {
        let seed = decode(vector.seed);
        let message: [u8; 32] = decode(vector.message).try_into().expect("32-byte message");

        // Deterministic key generation must reproduce the exact encapsulation key.
        let dk = DecapsulationKey::from_seed(&seed).expect("decapsulation key");
        let ek = dk.encapsulation_key();
        assert_eq!(
            hex::encode(ek.bytes()),
            vector.encapsulation_key,
            "vector {index}: encapsulation key mismatch"
        );

        // Derandomized encapsulation must reproduce the exact shared key and ciphertext.
        let (shared_key, ciphertext) = ek.encapsulate_deterministic(&message);
        assert_eq!(
            hex::encode(*shared_key),
            vector.shared_key,
            "vector {index}: shared key mismatch"
        );
        assert_eq!(
            hex::encode(ciphertext),
            vector.ciphertext,
            "vector {index}: ciphertext mismatch"
        );

        // Decapsulation must recover the same shared key from the ciphertext.
        let recovered = dk.decapsulate(&ciphertext).expect("decapsulate");
        assert_eq!(
            hex::encode(*recovered),
            vector.shared_key,
            "vector {index}: decapsulation mismatch"
        );

        // The encapsulation key must round-trip through its encoded form.
        let restored = EncapsulationKey::from_bytes(&decode(vector.encapsulation_key))
            .expect("restore encapsulation key");
        let (restored_shared, restored_ct) = restored.encapsulate_deterministic(&message);
        assert_eq!(
            hex::encode(*restored_shared),
            vector.shared_key,
            "vector {index}: restored shared mismatch"
        );
        assert_eq!(
            hex::encode(restored_ct),
            vector.ciphertext,
            "vector {index}: restored ciphertext mismatch"
        );
    }
}
